import vex
vex_client = vex.Client(api_key=os.getenv("VEX_API_KEY"))

def vex_rag_filter(sender, recipient, content, context):
    checks = {
        "source_faithfulness": context.get("sources", []),
        "hallucination_detection": True,
        "query_planning_accuracy": "planner" in sender.name,
        "cross_source_consistency": len(context.get("sources", [])) > 1
    }

    result = vex_client.verify({
        "content": content,
        "agent_role": sender.name,
        "checks": checks,
        "risk_profile": "high"
    })

    if not result["pass"]:
        return f"[VEX BLOCKED] {result['reason']}: {content}"
    return content

# Register globally
for agent in [planner, synthesizer, critic]:
    agent.register_reply(None, vex_rag_filter)

async def verify_source_faithfulness(content, sources):
    verification = await vex_client.verify({
        "type": "source_faithfulness",
        "claims": extract_claims(content),
        "sources": sources,
        "threshold": 0.85  # cosine similarity
    })

    failed_citations = []
    for claim, evidence in verification["matches"]:
        if evidence["similarity"] < 0.85:
            failed_citations.append(f"Claim '{claim}' not grounded")

    if failed_citations:
        raise ValueError("\n".join(failed_citations))
    return True

# In synthesizer reply handler
synthesizer.register_reply(critic, lambda msg: verify_source_faithfulness(msg["content"], msg["context"]["sources"]))
